scwin.popUp = async function () {
  if (ds_emp2.getCellData(ds_emp.getRowPosition(), "dcsnYn") != "2" || ds_emp2.getCellData(ds_emp.getRowPosition(), "dcsnDt") == "") {
    let data = {
      "ds_emp2": ds_emp2.getAllJSON(),
      cheCnt: scwin.cheCnt
    };
    let opts = {
      id: "smpPop",
      popupName: "할증할인선택",
      modal: false,
      width: 375,
      height: 470
    };

    //상세화면 호출 
    var rtn = await $c.win.openPopup($p, "/ui/ds/op/wrkrslts/transwrkrslts/op_304_03_02p.xml", opts, data);
    if (rtn == false) {
      return;
    }
    var arr = JSON.parse(rtn);
    ds_emp2.setJSON(arr);
    for (var i = 0; i <= ds_emp2.getRowCount(); i++) {
      if (ds_emp2.getCellData(i, "che") == "1") {
        ds_emp2.modifyRowStatus(i, "C");
      }
    }
    gr_emp2.setFocusedCell(0, 0);
  } else if (ds_emp2.getCellData(ds_emp.getRowPosition(), "dcsnYn") == "2") {
    $c.win.alert($p, "확인된 데이타는 수정할 수 없습니다.");
    return;
  }
};
scwin.gr_emp2_oncelldblclick = async function (rowIndex, columnIndex, columnId) {
  var row = rowIndex;
  if (rowIndex > 0) {
    var t = 0;
    var p = 0;
    var cur = 0;
    if (columnId == "dcScNm") {
      if (btn_Add.getDisabled() == true) {
        await $c.gus.cfAlertMsg($p, "등록 권한이 없습니다.");
        gr_emp2.setColumnReadOnly("dcScNm", true);
        return;
      }
      for (i = 0; i <= ds_emp2.getRowCount(); i++) {
        if (ds_emp2.getCellData(i, "transWrkIndictNo") == ds_emp2.getCellData(row, "transWrkIndictNo") && ds_emp2.getCellData(i, "transRsltsSeq") == ds_emp2.getCellData(row, "transRsltsSeq")) {
          t++;
          p = i;
        }
      }
      cur = p - t + 1;
      if (cur != rowIndex) {
        $c.win.alert($p, "추가된 항목이므로 더 이상 추가할 수 없습니다.");
        gr_emp2.setColumnReadOnly("dcScNm", true);
        return;
      } else {
        gr_emp2.setColumnReadOnly("dcScNm", true);
      }
    } else if (columnId == "confirmYn") {
      if (btn_Add.getDisabled() == true) {
        $c.gus.cfAlertMsg($p, "확인 권한이 없습니다.");
        gr_emp2.setColumnReadOnly("confirmYn", true);
        return;
      }
    } else if (columnId == "dcsnYn") {
      if (btn_Add.getDisabled() == true) {
        $c.gus.cfAlertMsg($p, "확인 권한이 없습니다.");
        gr_emp2.setColumnReadOnly("dcsnYn", true);
        return;
      }
    }
  } else {
    if (columnId == "che") {
      if (scwin.cheCnt == "1") {
        for (i = 0; i <= ds_emp2.getRowCount(); i++) {
          ds_emp2.setCellData(i, "che", "0");
        }
        scwin.cheCnt = "0";
      } else {
        for (i = 0; i <= ds_emp2.getRowCount(); i++) {
          ds_emp2.setCellData(i, "che", "1");
        }
        scwin.cheCnt = "1";
      }
    }
  }
};

