scwin.ds_emp_onrowpositionchange = async function (info) {
  var cntrCommSeq = "";
  var values = "";
  if (info.newRowIndex == null) {
    values = info.oldRowIndex;
  } else {
    values = info.newRowIndex;
  }
  if (ds_emp.getCellData(values, "wrkCls") == "C") {
    cntrCommSeq = ds_emp.getCellData(values, "cntrSeq");
  } else {
    cntrCommSeq = ds_emp.getCellData(values, "commSeq");
  }
  dma_retrieve2.set("transWrkIndictNo", ds_emp.getCellData(values, "transWrkIndictNo"));
  dma_retrieve2.set("transRsltsSeq", ds_emp.getCellData(values, "transRsltsSeq"));
  dma_retrieve2.set("wrkCls", ds_emp.getCellData(values, "wrkCls"));
  await $c.sbm.execute($p, sbm_retrieve2);
};
